  `sub_test_id` bigint(20) UNSIGNED DEFAULT NULL,
  `question` text NOT NULL,
  `option_a` text DEFAULT NULL,
  `option_a_image` varchar(255) DEFAULT NULL,
  `option_b` text DEFAULT NULL,
  `option_b_image` varchar(255) DEFAULT NULL,
  `option_c` text DEFAULT NULL,
  `option_c_image` varchar(255) DEFAULT NULL,
  `option_d` text DEFAULT NULL,
  `option_d_image` varchar(255) DEFAULT NULL,
  `option_e` varchar(500) DEFAULT NULL,
  `option_count` tinyint(3) UNSIGNED DEFAULT NULL,
  `correct_answer` char(1) DEFAULT NULL,
  `order` int(11) NOT NULL DEFAULT 0,
  `is_example` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `type` varchar(255) NOT NULL DEFAULT 'multiple_choice',
  `image` varchar(255) DEFAULT NULL,
  `image_data` longblob DEFAULT NULL,
  `image_mime` varchar(255) DEFAULT NULL,
  `audio` varchar(255) DEFAULT NULL,
  `correct_answer_text` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

